import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, UserPlus, Zap } from 'lucide-react';

const RegisterPage = () => {
  const { register } = useAuth();
  const { isDarkMode } = useTheme();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(null);

  const dynamicAutofillBg = isDarkMode ? '#000000' : '#ffffff';
  const dynamicAutofillText = isDarkMode ? '#ffffff' : '#000000';

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.password || !formData.confirmPassword) {
      return toast.error('INPUT_REQUIRED: Fill all fields');
    }
    if (formData.password !== formData.confirmPassword) {
      return toast.error('SECURITY_ERROR: Passwords mismatch');
    }
    setLoading(true);
    try {
      await register(formData);
      toast.success('NODE_DEPLOYED');
      navigate('/login');
    } catch (error) {
      toast.error('REGISTRATION_FAILED');
    } finally {
      setLoading(false);
    }
  };

  /* ───────── Glow-Enhanced Styles ───────── */
  const inputStyle = (fieldId, extra = {}) => ({
    width: '100%',
    boxSizing: 'border-box',
    WebkitBoxShadow: `0 0 0px 1000px ${dynamicAutofillBg} inset`,
    WebkitTextFillColor: dynamicAutofillText,
    caretColor: 'var(--accent-primary)',
    // DYNAMIC GLOW BORDER
    border: `1px solid ${focused === fieldId ? 'var(--accent-primary)' : 'var(--surface-border)'}`,
    boxShadow: focused === fieldId ? '0 0 15px var(--accent-glow)' : 'none',
    background: 'var(--bg-main)',
    color: 'var(--text-primary)',
    padding: '0.9rem 1.1rem',
    borderRadius: '14px',
    outline: 'none',
    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
    ...extra,
  });

  const labelStyle = (field) => ({
    display: 'block', 
    fontSize: '0.65rem', 
    fontWeight: 800,
    textTransform: 'uppercase', 
    letterSpacing: '0.15em',
    // GLOWING LABEL TEXT
    color: focused === field ? 'var(--accent-primary)' : 'var(--text-muted)',
    textShadow: focused === field ? '0 0 8px var(--accent-glow)' : 'none',
    marginBottom: '0.6rem', 
    transition: 'all 0.3s ease',
  });

  return (
    <div style={pageWrapper}>
      {/* Background Ambience */}
      <div aria-hidden="true" style={glowTopLeft} />
      <div aria-hidden="true" style={glowBottomRight} />

      {/* Register Card */}
      <div className="reveal-node glow-card" style={cardStyle}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '2.5rem' }}>
          <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '1.2rem' }}>
            <div style={iconContainer}>
              <UserPlus size={24} color="var(--accent-primary)" style={{ filter: 'drop-shadow(0 0 5px var(--accent-primary))' }} />
            </div>
          </div>
          <h1 style={titleStyle}>Initialize Node</h1>
          <p style={subtitleStyle}>Create your master credentials</p>
        </div>

        <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '1.4rem' }}>
          <div>
            <label htmlFor="name" style={labelStyle('name')}>Full Name</label>
            <input
              id="name"
              type="text"
              placeholder="Operator Name"
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
              onFocus={() => setFocused('name')}
              onBlur={() => setFocused(null)}
              autoComplete="name"
              style={inputStyle('name')}
            />
          </div>

          <div>
            <label htmlFor="email" style={labelStyle('email')}>Email Address</label>
            <input
              id="email"
              type="email"
              placeholder="operator@finify.ai"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
              onFocus={() => setFocused('email')}
              onBlur={() => setFocused(null)}
              autoComplete="email"
              style={inputStyle('email')}
            />
          </div>

          <div>
            <label htmlFor="password" style={labelStyle('password')}>Master Key</label>
            <div style={{ position: 'relative' }}>
              <input
                id="password"
                type={showPassword ? 'text' : 'password'}
                placeholder="••••••••"
                value={formData.password}
                onChange={e => setFormData({...formData, password: e.target.value})}
                onFocus={() => setFocused('password')}
                onBlur={() => setFocused(null)}
                autoComplete="new-password"
                style={inputStyle('password', { paddingRight: '3.5rem' })}
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)} style={eyeBtnStyle}>
                {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>
          </div>

          <div>
            <label htmlFor="confirmPassword" style={labelStyle('confirmPassword')}>Confirm Master Key</label>
            <div style={{ position: 'relative' }}>
              <input
                id="confirmPassword"
                type={showConfirmPassword ? 'text' : 'password'}
                placeholder="••••••••"
                value={formData.confirmPassword}
                onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
                onFocus={() => setFocused('confirmPassword')}
                onBlur={() => setFocused(null)}
                autoComplete="new-password"
                style={inputStyle('confirmPassword', { paddingRight: '3.5rem' })}
              />
              <button type="button" onClick={() => setShowConfirmPassword(!showConfirmPassword)} style={eyeBtnStyle}>
                {showConfirmPassword ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>
          </div>

          <button type="submit" className="cyber-btn glow-button" disabled={loading} style={deployBtnStyle}>
            {loading ? <Zap size={18} className="animate-pulse" /> : 'DEPLOY_NODE'}
          </button>
        </form>

        <div style={footerStyle}>
          <p style={footerText}>
            Existing Operator?{' '}
            <Link to="/login" style={linkStyle}>Log in</Link>
          </p>
        </div>
      </div>

      <style>{`
        .glow-card:hover {
          border-color: var(--accent-primary) !important;
          box-shadow: 0 0 30px var(--accent-glow), var(--shadow-elevated) !important;
        }
        .glow-button {
